sys_script_include.script:
var AROPCheckSeeder_WSD = Class.create();
AROPCheckSeeder_WSD.prototype = {
    initialize: function() {},
    getChecks: function() {
        return [{"module":"WSD","check_name":"Now Assist for WSD Plugin Status","order":"100","check_script":"(function() { var gr = new GlideRecord(\"sys_store_app\"); gr.addQuery(\"scope\", \"sn_now_assist_wsd\"); gr.setLimit(1); gr.query(); if (gr.next()) { return { status: \"ready\", actualValue: \"Now Assist for WSD is active\", finding: \"Now Assist for Workplace Service Delivery is active. AI-powered space recommendations, reservation summarization, and workplace insights are available.\" }; } var gr2 = new GlideRecord(\"sys_plugins\"); gr2.addQuery(\"id\", \"sn_now_assist_wsd\"); gr2.addQuery(\"active\", true); gr2.setLimit(1); gr2.query(); if (gr2.next()) { return { status: \"ready\", actualValue: \"Now Assist for WSD is active\", finding: \"Now Assist for Workplace Service Delivery is active. AI-powered space recommendations and workplace insights are available.\" }; } return { status: \"not_ready\", actualValue: \"Now Assist for WSD not found or inactive\", finding: \"Now Assist for WSD is not active. All AI-powered workplace service delivery capabilities are unavailable without this plugin.\" }; })","ai_justification":"Now Assist for WSD is the foundational plugin enabling all AI capabilities for workplace service delivery including space recommendations, reservation summarization, and occupancy insights. Without it no AI features are available regardless of data quality.","remediation_guidance":"Activate Now Assist for Workplace Service Delivery via the ServiceNow Store. Confirm entitlement with your ServiceNow account team before activation.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"Space Inventory Volume","order":"200","check_script":"(function() { var ga = new GlideAggregate(\"sn_wsd_core_space\"); ga.addAggregate(\"COUNT\"); ga.query(); var total = ga.next() ? parseInt(ga.getAggregate(\"COUNT\")) : 0; if (total >= 100) { return { status: \"ready\", actualValue: total + \" space records in inventory\", finding: total + \" spaces. Now Assist WSD has sufficient space data for AI-powered space recommendations and occupancy analysis.\" }; } else if (total >= 20) { return { status: \"needs_attention\", actualValue: total + \" space records in inventory\", finding: \"Only \" + total + \" spaces (target: 100+). Now Assist WSD AI space recommendations will have limited coverage.\" }; } else { return { status: \"not_ready\", actualValue: total + \" space records in inventory\", finding: \"Only \" + total + \" spaces. Insufficient space data for meaningful Now Assist WSD AI recommendations.\" }; } })","ai_justification":"Space inventory is the core dataset Now Assist WSD uses for AI space recommendations. Without sufficient space records, AI cannot suggest appropriate workspaces or analyze occupancy patterns.","remediation_guidance":"Populate the space inventory in Workplace Core. Import floor plans and space data to ensure Now Assist WSD has sufficient space records for AI-powered recommendations.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"Space Capacity Data Population","order":"300","check_script":"(function() { var gaTotal = new GlideAggregate(\"sn_wsd_core_space\"); gaTotal.addAggregate(\"COUNT\"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate(\"COUNT\")) : 0; if (total === 0) { return { status: \"not_ready\", actualValue: \"No space records found\", finding: \"No space records found. Capacity data cannot be assessed.\" }; } var gaCap = new GlideAggregate(\"sn_wsd_core_space\"); gaCap.addQuery(\"capacity\", \">\", \"0\"); gaCap.addAggregate(\"COUNT\"); gaCap.query(); var withCap = gaCap.next() ? parseInt(gaCap.getAggregate(\"COUNT\")) : 0; var pct = Math.round((withCap / total) * 100); var actualValue = pct + \"% of spaces have capacity data (\" + withCap + \"/\" + total + \")\"; if (pct >= 90) { return { status: \"ready\", actualValue: actualValue, finding: pct + \"% of spaces have capacity configured. Now Assist WSD can accurately match group sizes to appropriate spaces in AI recommendations.\" }; } else if (pct >= 70) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Only \" + pct + \"% of spaces have capacity data (target: 90%+). Now Assist WSD AI space matching accuracy will be reduced.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"Only \" + pct + \"% of spaces have capacity data. Now Assist WSD cannot accurately match group sizes to spaces without capacity information.\" }; } })","ai_justification":"Space capacity is a primary matching criterion Now Assist WSD uses for AI space recommendations. Without capacity data, AI cannot determine whether a space is appropriate for the number of attendees requested.","remediation_guidance":"Populate the capacity field on all space records in Workplace Core. Capacity data is required for Now Assist WSD to accurately recommend spaces that fit the size of the booking group.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"Reservation Volume","order":"400","check_script":"(function() { var cutoff = new GlideDateTime(); cutoff.addYearsUTC(-1); var ga = new GlideAggregate(\"sn_wsd_rsv_reservation\"); ga.addQuery(\"sys_created_on\", \">=\", cutoff.getValue()); ga.addAggregate(\"COUNT\"); ga.query(); var count = ga.next() ? parseInt(ga.getAggregate(\"COUNT\")) : 0; if (count >= 500) { return { status: \"ready\", actualValue: count + \" reservations in last 12 months\", finding: count + \" reservations in the last 12 months. Now Assist WSD has sufficient reservation history for AI occupancy analysis and space utilization insights.\" }; } else if (count >= 100) { return { status: \"needs_attention\", actualValue: count + \" reservations in last 12 months\", finding: \"Only \" + count + \" reservations in the last 12 months (target: 500+). Now Assist WSD AI occupancy analysis will have limited pattern data.\" }; } else { return { status: \"not_ready\", actualValue: count + \" reservations in last 12 months\", finding: \"Only \" + count + \" reservations in the last 12 months. Insufficient reservation history for meaningful Now Assist WSD AI occupancy analysis.\" }; } })","ai_justification":"Reservation history is the primary dataset Now Assist WSD uses for AI occupancy analysis and space utilization insights. Without sufficient reservation data, AI cannot identify utilization patterns or generate accurate space optimization recommendations.","remediation_guidance":"Ensure all workplace reservations are captured in ServiceNow WSD. If volume is low due to recent implementation, allow reservation data to accumulate before expecting optimal AI performance.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"Campus Configuration","order":"500","check_script":"(function() { var ga = new GlideAggregate(\"sn_wsd_core_campus\"); ga.addAggregate(\"COUNT\"); ga.query(); var count = ga.next() ? parseInt(ga.getAggregate(\"COUNT\")) : 0; if (count >= 3) { return { status: \"ready\", actualValue: count + \" campus records configured\", finding: count + \" campuses configured. Now Assist WSD has structured location hierarchy for AI-powered location-aware space recommendations.\" }; } else if (count >= 1) { return { status: \"needs_attention\", actualValue: count + \" campus record(s) configured\", finding: \"Only \" + count + \" campus configured (target: 3+). Now Assist WSD AI location-based recommendations may have limited geographic coverage.\" }; } else { return { status: \"not_ready\", actualValue: \"No campus records configured\", finding: \"No campuses configured. Now Assist WSD cannot provide location-aware AI space recommendations without campus structure.\" }; } })","ai_justification":"Campus configuration provides the location hierarchy Now Assist WSD uses for AI-powered location-aware space recommendations. Without campus structure, AI cannot filter space recommendations by employee location or proximity preferences.","remediation_guidance":"Configure campus records for each physical location in Workplace Core. Navigate to Workplace Service Delivery > Administration > Campuses to create campus records.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"Reservable Module Configuration","order":"600","check_script":"(function() { var ga = new GlideAggregate(\"sn_wsd_rsv_reservable_module\"); ga.addAggregate(\"COUNT\"); ga.query(); var count = ga.next() ? parseInt(ga.getAggregate(\"COUNT\")) : 0; if (count >= 3) { return { status: \"ready\", actualValue: count + \" reservable modules configured\", finding: count + \" reservable modules configured. Now Assist WSD can recommend across multiple space types including desks, meeting rooms, and amenity spaces.\" }; } else if (count >= 1) { return { status: \"needs_attention\", actualValue: count + \" reservable module(s) configured\", finding: \"Only \" + count + \" reservable module(s) configured (target: 3+). Now Assist WSD AI recommendations will be limited to fewer space types.\" }; } else { return { status: \"not_ready\", actualValue: \"No reservable modules configured\", finding: \"No reservable modules configured. Now Assist WSD cannot make AI space recommendations without defined reservable space types.\" }; } })","ai_justification":"Reservable modules define the types of spaces Now Assist WSD can recommend. Without multiple module types, AI recommendations are limited in variety and cannot match employee preferences for different workspace types.","remediation_guidance":"Configure reservable modules for each space type (desks, meeting rooms, focus rooms, etc.). Navigate to Workplace Service Delivery > Administration > Reservable Modules.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"Check-in Configuration","order":"700","check_script":"(function() { var gaTotal = new GlideAggregate(\"sn_wsd_rsv_reservation\"); gaTotal.addAggregate(\"COUNT\"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate(\"COUNT\")) : 0; if (total === 0) { return { status: \"not_applicable\", actualValue: \"No reservations found\", finding: \"No reservations found. Check-in configuration cannot be assessed.\" }; } var gaCheckin = new GlideAggregate(\"sn_wsd_rsv_reservation\"); gaCheckin.addQuery(\"check_in_state\", \"awaiting_check_in\"); gaCheckin.addAggregate(\"COUNT\"); gaCheckin.query(); var awaiting = gaCheckin.next() ? parseInt(gaCheckin.getAggregate(\"COUNT\")) : 0; var pct = Math.round((awaiting / total) * 100); var actualValue = pct + \"% of reservations use check-in (\" + awaiting + \"/\" + total + \")\"; if (pct >= 50) { return { status: \"ready\", actualValue: actualValue, finding: pct + \"% of reservations have check-in enabled. Now Assist WSD has occupancy confirmation data for accurate AI space utilization analysis.\" }; } else if (pct >= 20) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Only \" + pct + \"% of reservations use check-in (target: 50%+). Now Assist WSD AI occupancy data will be based on reservations rather than confirmed attendance.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"Only \" + pct + \"% of reservations use check-in. Now Assist WSD AI occupancy analysis will be inaccurate without check-in confirmation data.\" }; } })","ai_justification":"Check-in data provides Now Assist WSD with confirmed occupancy signals beyond reservation intent. Without check-in data, AI occupancy analysis is based on reservations rather than actual attendance, leading to inaccurate space utilization insights.","remediation_guidance":"Enable check-in requirements on reservable modules. Check-in data provides Now Assist WSD with confirmed occupancy signals for accurate AI space utilization analysis and ghost reservation detection.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"WSD Workspace Activation","order":"800","check_script":"(function() { var gr = new GlideRecord(\"sys_store_app\"); gr.addQuery(\"scope\", \"sn_wsd_core\"); gr.setLimit(1); gr.query(); if (gr.next()) { return { status: \"ready\", actualValue: \"Workplace Core (\" + gr.getValue(\"name\") + \") is active\", finding: \"Workplace Core is active. Now Assist WSD AI insights including space recommendations and occupancy analysis are accessible to workplace managers and employees.\" }; } var gr2 = new GlideRecord(\"sys_plugins\"); gr2.addQuery(\"id\", \"sn_wsd_workspace\"); gr2.addQuery(\"active\", true); gr2.setLimit(1); gr2.query(); if (gr2.next()) { return { status: \"ready\", actualValue: \"Workplace Service Delivery Workspace is active\", finding: \"WSD Workspace is active. Now Assist WSD AI insights are surfaced in context for workplace managers.\" }; } return { status: \"not_ready\", actualValue: \"WSD Workspace not found or inactive\", finding: \"WSD Workspace is not active. Now Assist WSD AI insights are not accessible in a contextually relevant interface.\" }; })","ai_justification":"The WSD Workspace is the primary interface where Now Assist WSD AI insights are presented to managers and employees. Without it, AI-generated space recommendations and occupancy insights are produced but never surfaced where they are needed.","remediation_guidance":"Activate the Workplace Service Delivery workspace via the ServiceNow Store or Plugin Manager. The workspace is required for Now Assist WSD AI insights to surface in context.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"Location Coverage on Spaces","order":"900","check_script":"(function() { var gaTotal = new GlideAggregate(\"sn_wsd_core_space\"); gaTotal.addAggregate(\"COUNT\"); gaTotal.query(); var total = gaTotal.next() ? parseInt(gaTotal.getAggregate(\"COUNT\")) : 0; if (total === 0) { return { status: \"not_ready\", actualValue: \"No space records found\", finding: \"No space records found. Location coverage cannot be assessed.\" }; } var gaLoc = new GlideAggregate(\"sn_wsd_core_space\"); gaLoc.addQuery(\"building\", \"!=\", \"\"); gaLoc.addAggregate(\"COUNT\"); gaLoc.query(); var withBuilding = gaLoc.next() ? parseInt(gaLoc.getAggregate(\"COUNT\")) : 0; var pct = Math.round((withBuilding / total) * 100); var actualValue = pct + \"% of spaces have a building assigned (\" + withBuilding + \"/\" + total + \")\"; if (pct >= 90) { return { status: \"ready\", actualValue: actualValue, finding: pct + \"% of spaces have building assignments. Now Assist WSD can provide accurate location-aware AI space recommendations.\" }; } else if (pct >= 60) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Only \" + pct + \"% of spaces have building assignments (target: 90%+). Now Assist WSD AI location filtering will have incomplete coverage.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"Only \" + pct + \"% of spaces have building assignments. Now Assist WSD cannot provide location-aware AI recommendations without building data on spaces.\" }; } })","ai_justification":"Building assignments on space records enable Now Assist WSD to provide location-aware AI space recommendations. Without building data, AI cannot filter spaces by proximity to the employee or their team.","remediation_guidance":"Assign building references to all space records in Workplace Core. Building data is required for Now Assist WSD to filter and recommend spaces by employee location.","is_manual":"0","is_clone_sensitive":"0"},{"module":"WSD","check_name":"WSD Customization Risk","order":"1000","check_script":"(function() { var ga1 = new GlideAggregate(\"sys_script\"); ga1.addQuery(\"collection\", \"sn_wsd_rsv_reservation\"); ga1.addQuery(\"active\", true); ga1.addQuery(\"sys_created_by\", \"NOT IN\", \"glide.maint,system,admin,fred.luddy\"); ga1.addAggregate(\"COUNT\"); ga1.query(); var brs1 = ga1.next() ? parseInt(ga1.getAggregate(\"COUNT\")) : 0; var ga2 = new GlideAggregate(\"sys_script\"); ga2.addQuery(\"collection\", \"sn_wsd_core_space\"); ga2.addQuery(\"active\", true); ga2.addQuery(\"sys_created_by\", \"NOT IN\", \"glide.maint,system,admin,fred.luddy\"); ga2.addAggregate(\"COUNT\"); ga2.query(); var brs2 = ga2.next() ? parseInt(ga2.getAggregate(\"COUNT\")) : 0; var risk = brs1 + brs2; var actualValue = brs1 + \" custom BRs on reservations + \" + brs2 + \" on spaces (risk score: \" + risk + \")\"; if (risk <= 5) { return { status: \"ready\", actualValue: actualValue, finding: \"Low WSD customization risk (score: \" + risk + \"). Now Assist WSD AI recommendations are unlikely to encounter conflicts with existing customizations.\" }; } else if (risk <= 10) { return { status: \"needs_attention\", actualValue: actualValue, finding: \"Moderate WSD customization risk (score: \" + risk + \"). Test Now Assist WSD in sub-production before enabling in production.\" }; } else { return { status: \"not_ready\", actualValue: actualValue, finding: \"High WSD customization risk (score: \" + risk + \"). Extensive customization increases the risk of conflicts with Now Assist WSD AI actions.\" }; } })","ai_justification":"Custom Business Rules on WSD tables can intercept or conflict with Now Assist WSD AI recommendation actions. High customization density increases the risk of AI recommendations failing or producing unexpected results.","remediation_guidance":"Review custom Business Rules on sn_wsd_rsv_reservation and sn_wsd_core_space tables. Test Now Assist WSD in sub-production to identify and resolve conflicts before enabling in production.","is_manual":"0","is_clone_sensitive":"0"}];
    },
    type: 'AROPCheckSeeder_WSD'
};
